<template>
  <div class="columns is-centered">
    <div class="column is-two-thirds-desktop">
      <div class="buttons is-centered has-text-weight-bold" :class="hasAddons">
        <a @click="$router.go(-1)" class="button is-rounded" :class="[isFull, bgColor]">
          <b-icon icon="chevron-circle-left"></b-icon>&emsp;Go back
        </a>
        <router-link :to="next" :class="[isFull, bgColor]" class="button is-rounded has-text-primary">
          {{text}}&emsp;
          <b-icon icon="chevron-circle-right"></b-icon>
        </router-link>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  created() {
    let checkWidth = debounce(this.getWidth, 250);
    window.addEventListener("resize", checkWidth);
    window.addEventListener("load", checkWidth);
    function debounce(fn, delay) {
      var timeoutID = null;
      return function() {
        clearTimeout(timeoutID);
        var args = arguments;
        var that = this;
        timeoutID = setTimeout(function() {
          fn.apply(that, args);
        }, delay);
      };
    }
  },
  data() {
    return {
      hasAddons: "has-addons",
      bgColor: "is-light",
      isFull: null
    };
  },
  props: {
    next: String,
    text: String
  },
  methods: {
    getWidth() {
      if (window.innerWidth > 632) {
        this.hasAddons = "has-addons";
        this.bgColor = "is-light";
        this.isFull = null;
      } else {
        this.hasAddons = null;
        this.bgColor = "is-white";
        this.isFull = "is-fullwidth";
      }
    }
  }
};
</script>